const runDate = new Date($json.timestamp);

// Go back to last Monday
const day = runDate.getDay(); // Sun=0, Mon=1
const diffToLastMonday = day === 0 ? 6 : day - 1;

const lastMonday = new Date(runDate);
lastMonday.setDate(runDate.getDate() - diffToLastMonday - 7);
lastMonday.setHours(0, 0, 0, 0);

// Last Sunday
const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);
lastSunday.setHours(23, 59, 59, 999);

return [{
  json: {
    lastWeekStart: lastMonday.toISOString(),
    lastWeekEnd: lastSunday.toISOString()
  }
}];

let totalRevenue = 0;
let validOrders = 0;

items.forEach(item => {
  const o = item.json;

  if (!['completed', 'processing'].includes(o.status)) return;
  if (!o.line_items || o.line_items.length === 0) return;
  if (parseFloat(o.total) <= 0) return;

  validOrders++;
  totalRevenue += parseFloat(o.total);
});

return [{
  json: {
    total_orders: validOrders,
    total_revenue: totalRevenue,
    average_order_value: validOrders > 0 ? totalRevenue / validOrders : 0
  }
}];

let refundCount = 0;
let refundAmount = 0;

items.forEach(item => {
  refundCount++;

  const amount = parseFloat(item.json.amount);
  if (amount > 0) {
    refundAmount += amount;
  }

  // If line_items exist, sum negatives
  if (item.json.line_items?.length) {
    item.json.line_items.forEach(li => {
      refundAmount += Math.abs(parseFloat(li.total));
    });
  }
});

return [{
  json: {
    refund_count: refundCount,
    refund_amount: refundAmount
  }
}];

const productMap = {};

// Loop through all orders
items.forEach(order => {
  const o = order.json;

  // Skip invalid orders
  if (!o.line_items || o.line_items.length === 0) return;
  if (!['completed', 'processing'].includes(o.status)) return;

  o.line_items.forEach(item => {
    const productId = item.product_id;

    if (!productMap[productId]) {
      productMap[productId] = {
        product_name: item.name,
        total_quantity: 0,
        total_revenue: 0
      };
    }

    productMap[productId].total_quantity += item.quantity;
    productMap[productId].total_revenue += parseFloat(item.total);
  });
});

// Sort by revenue (more useful for leadership)
const topProducts = Object.values(productMap)
  .sort((a, b) => b.total_revenue - a.total_revenue)
  .slice(0, 5);

// Format into report-ready text
const topProductsText = topProducts
  .map((p, i) => `${i + 1}. ${p.product_name} (₹${p.total_revenue})`)
  .join(', ');

// ✅ Single KPI output
return [{
  json: {
    top_products: topProductsText
  }
}];

